1703	\begin{lemma}
1704	\label{lemma-separable-first}
1705	\begin{slogan}
1706	Any algebraic field extension is uniquely a separable field extension
1707	followed by a purely inseparable one.
1708	\end{slogan}
1709	Let $E/F$ be an algebraic field extension. There exists a unique subextension
1710	$E/E_{sep}/F$ such that $E_{sep}/F$ is separable and $E/E_{sep}$ is
1711	purely inseparable.
1712	\end{lemma}
1713	
1714	\begin{proof}
1715	If the characteristic is zero we set $E_{sep} = E$. Assume the characteristic
1716	is $p > 0$. Let $E_{sep}$ be the set of elements of $E$ which are separable
1717	over $F$. This is a subextension by Lemma \ref{lemma-separable-elements}
1718	and of course $E_{sep}$ is separable over $F$. Given an $\alpha$ in $E$
1719	there exists a $p$-power $q$ such that $\alpha^q$ is separable over $F$.
1720	Namely, $q$ is that power of $p$ such that the minimal polynomial of
1721	$\alpha$ is of the form $P(x^q)$ with $P$ separable algebraic, see
1722	Lemma \ref{lemma-irreducible-polynomials}. Hence $E/E_{sep}$ is purely
1723	inseparable. Uniqueness is clear.
1724	\end{proof}
1725	
1726	\begin{definition}
1727	\label{definition-insep-degree}
1728	Let $E/F$ be an algebraic field extension. Let $E_{sep}$ be the subextension
1729	found in Lemma \ref{lemma-separable-first}.
1730	\begin{enumerate}
1731	\item The integer $[E_{sep} : F]$ is called the {\it separable
1732	degree} of the extension. Notation $[E : F]_s$.
1733	\item The integer $[E : E_{sep}]$ is called the {\it inseparable
1734	degree}, or the {\it degree of inseparability} of the extension.
